const visit = $input.first().json;
const actions = [];

// Acción de seguimiento siempre
actions.push({
  lead_id: visit.lead_id,
  title: `Seguimiento post-visita: ${visit.company_name || 'Lead'}`,
  description: `Resultado visita: ${visit.result || 'sin resultado'}. ${visit.summary || ''}`,
  due_date: new Date(Date.now() + 3 * 86400000).toISOString().split('T')[0],
  priority: visit.result === 'positive' ? 'high' : 'medium',
  action_type: 'follow_up'
});

// Si hay próximos pasos, crear acción por cada uno
const nextSteps = visit.next_steps || [];
nextSteps.forEach((step, i) => {
  actions.push({
    lead_id: visit.lead_id,
    title: step,
    description: `Paso acordado en visita del ${new Date().toLocaleDateString('es-ES')}`,
    due_date: new Date(Date.now() + (7 + i * 3) * 86400000).toISOString().split('T')[0],
    priority: 'medium',
    action_type: 'task'
  });
});

// Si resultado negativo, acción de revisión
if (visit.result === 'negative') {
  actions.push({
    lead_id: visit.lead_id,
    title: `Revisión estrategia: ${visit.company_name || 'Lead'}`,
    description: 'Resultado negativo en visita. Revisar enfoque y decidir próximos pasos.',
    due_date: new Date(Date.now() + 7 * 86400000).toISOString().split('T')[0],
    priority: 'low',
    action_type: 'review'
  });
}

return actions.map(a => ({ json: a }));

